          console.log('[FIELD ASSIGNMENT] =========================================');
          console.log('[LIVE EXTRACTION MAPPED] serviceRequested:', intake.serviceRequested);
          
          // STAGE 3: Extraction Function Output
          console.log('[EXTRACTION TRACE STAGE 3] =========================================');
