                    console.log('[SILENCE TIMEOUT TRIGGERED] validUserAnswerReceivedAt:', callSessionState.validUserAnswerReceivedAt);
                    console.log('[SILENCE TIMEOUT TRIGGERED] repromptCount:', callSessionState.repromptCount);
